import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';
import { OAuth2 } from 'oauth2-client';

const clientId = 'mobile_app_client_123';
const clientSecret = 'secret_abc123xyz456';

function Authenticate() {
  const [code, setCode] = useState('');
  const [token, setToken] = useState('');

  const handleAuth = async () => {
    try {
      const oauth = new OAuth2({ clientId, clientSecret });
      const authorizationUrl = await oauth.authorizationCode.generateAuthorizationUrl();
      console.log(authorizationUrl);
      setCode('');
    } catch (error) {
      console.error(error);
    }
  };

  const handleToken = async () => {
    try {
      const oauth = new OAuth2({ clientId, clientSecret });
      const tokenResponse = await oauth.authorizationCode.getToken(code);
      console.log(tokenResponse);
      setToken('');
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <View>
      <Text>Authenticate</Text>
      <Button title="Authorize" onPress={handleAuth} />
      <Text>{code}</Text>
      <Button title="Get Token" onPress={handleToken} />
      <Text>{token}</Text>
    </View>
  );
}